153	
154	  const providerName = options.name ?? 'openai';
155	
156	  const getHeaders = () =>
157	    withUserAgentSuffix(
158	      {
159	        Authorization: `Bearer ${loadApiKey({
160	          apiKey: options.apiKey,
161	          environmentVariableName: 'OPENAI_API_KEY',
162	          description: 'OpenAI',
163	        })}`,
164	        'OpenAI-Organization': options.organization,
165	        'OpenAI-Project': options.project,
166	        ...options.headers,
167	      },
168	      `ai-sdk/openai/${VERSION}`,
169	    );
170	
171	  const createChatModel = (modelId: OpenAIChatModelId) =>
172	    new OpenAIChatLanguageModel(modelId, {
173	      provider: `${providerName}.chat`,
174	      url: ({ path }) => `${baseURL}${path}`,
175	      headers: getHeaders,
176	      fetch: options.fetch,
177	    });
178	
179	  const createCompletionModel = (modelId: OpenAICompletionModelId) =>
180	    new OpenAICompletionLanguageModel(modelId, {
181	      provider: `${providerName}.completion`,
182	      url: ({ path }) => `${baseURL}${path}`,
183	      headers: getHeaders,
184	      fetch: options.fetch,
185	    });
186	
187	  const createEmbeddingModel = (modelId: OpenAIEmbeddingModelId) =>
188	    new OpenAIEmbeddingModel(modelId, {
189	      provider: `${providerName}.embedding`,
190	      url: ({ path }) => `${baseURL}${path}`,
191	      headers: getHeaders,
192	      fetch: options.fetch,
193	    });
194	
195	  const createImageModel = (modelId: OpenAIImageModelId) =>
196	    new OpenAIImageModel(modelId, {
197	      provider: `${providerName}.image`,
198	      url: ({ path }) => `${baseURL}${path}`,
199	      headers: getHeaders,
200	      fetch: options.fetch,
201	    });
202	
203	  const createTranscriptionModel = (modelId: OpenAITranscriptionModelId) =>
204	    new OpenAITranscriptionModel(modelId, {
205	      provider: `${providerName}.transcription`,
206	      url: ({ path }) => `${baseURL}${path}`,
207	      headers: getHeaders,
208	      fetch: options.fetch,
209	    });
210	
211	  const createSpeechModel = (modelId: OpenAISpeechModelId) =>
212	    new OpenAISpeechModel(modelId, {
213	      provider: `${providerName}.speech`,
214	      url: ({ path }) => `${baseURL}${path}`,
215	      headers: getHeaders,
216	      fetch: options.fetch,
217	    });
218	
219	  const createLanguageModel = (modelId: OpenAIResponsesModelId) => {
220	    if (new.target) {
221	      throw new Error(
222	        'The OpenAI model function cannot be called with the new keyword.',
223	      );
224	    }
225	
226	    return createResponsesModel(modelId);
227	  };
228	
229	  const createResponsesModel = (modelId: OpenAIResponsesModelId) => {
230	    return new OpenAIResponsesLanguageModel(modelId, {
231	      provider: `${providerName}.responses`,
232	      url: ({ path }) => `${baseURL}${path}`,
233	      headers: getHeaders,
234	      fetch: options.fetch,
235	      fileIdPrefixes: ['file-'],
236	    });
237	  };
238	
239	  const provider = function (modelId: OpenAIResponsesModelId) {
240	    return createLanguageModel(modelId);
241	  };
242	
243	  provider.specificationVersion = 'v3' as const;
244	  provider.languageModel = createLanguageModel;
245	  provider.chat = createChatModel;
246	  provider.completion = createCompletionModel;
247	  provider.responses = createResponsesModel;
248	  provider.embedding = createEmbeddingModel;
249	  provider.embeddingModel = createEmbeddingModel;
250	  provider.textEmbedding = createEmbeddingModel;
251	  provider.textEmbeddingModel = createEmbeddingModel;
252	
253	  provider.image = createImageModel;
254	  provider.imageModel = createImageModel;
255	
256	  provider.transcription = createTranscriptionModel;
257	  provider.transcriptionModel = createTranscriptionModel;
258	
259	  provider.speech = createSpeechModel;
260	  provider.speechModel = createSpeechModel;
261	
262	  provider.tools = openaiTools;
263	
264	  return provider as OpenAIProvider;
265	}
