15	  buildProdiaProviderMetadata,
16	  parseMultipart,
17	  prodiaFailedResponseHandler,
18	  prodiaJobResultSchema,
19	} from './prodia-api';
20	import type { ProdiaJobResult } from './prodia-api';
21	import type { ProdiaImageModelId } from './prodia-image-settings';
22	
23	export class ProdiaImageModel implements ImageModelV3 {
24	  readonly specificationVersion = 'v3';
25	  readonly maxImagesPerCall = 1;
26	
27	  get provider(): string {
28	    return this.config.provider;
29	  }
30	
31	  constructor(
32	    readonly modelId: ProdiaImageModelId,
33	    private readonly config: ProdiaModelConfig,
34	  ) {}
35	
36	  private async getArgs({
37	    prompt,
38	    size,
39	    seed,
40	    providerOptions,
41	  }: Parameters<ImageModelV3['doGenerate']>[0]) {
42	    const warnings: Array<SharedV3Warning> = [];
43	
44	    const prodiaOptions = await parseProviderOptions({
45	      provider: 'prodia',
46	      providerOptions,
47	      schema: prodiaImageModelOptionsSchema,
48	    });
49	
50	    let width: number | undefined;
51	    let height: number | undefined;
52	    if (size) {
53	      const [widthStr, heightStr] = size.split('x');
54	      width = Number(widthStr);
55	      height = Number(heightStr);
56	      if (
57	        !widthStr ||
58	        !heightStr ||
59	        !Number.isFinite(width) ||
60	        !Number.isFinite(height)
61	      ) {
62	        warnings.push({
63	          type: 'unsupported',
64	          feature: 'size',
65	          details: `Invalid size format: ${size}. Expected format: WIDTHxHEIGHT (e.g., 1024x1024)`,
66	        });
67	        width = undefined;
68	        height = undefined;
69	      }
70	    }
71	
72	    const jobConfig: Record<string, unknown> = {
73	      prompt,
74	    };
75	
76	    if (prodiaOptions?.width !== undefined) {
77	      jobConfig.width = prodiaOptions.width;
78	    } else if (width !== undefined) {
79	      jobConfig.width = width;
80	    }
81	
82	    if (prodiaOptions?.height !== undefined) {
83	      jobConfig.height = prodiaOptions.height;
84	    } else if (height !== undefined) {
85	      jobConfig.height = height;
86	    }
87	
88	    if (seed !== undefined) {
89	      jobConfig.seed = seed;
90	    }
91	    if (prodiaOptions?.steps !== undefined) {
92	      jobConfig.steps = prodiaOptions.steps;
93	    }
94	    if (prodiaOptions?.stylePreset !== undefined) {
95	      jobConfig.style_preset = prodiaOptions.stylePreset;
96	    }
97	    if (prodiaOptions?.loras !== undefined && prodiaOptions.loras.length > 0) {
98	      jobConfig.loras = prodiaOptions.loras;
99	    }
100	    if (prodiaOptions?.progressive !== undefined) {
101	      jobConfig.progressive = prodiaOptions.progressive;
102	    }
103	
104	    const body = {
105	      type: this.modelId,
106	      config: jobConfig,
107	    };
108	
109	    return { body, warnings };
110	  }
111	
112	  async doGenerate(
113	    options: Parameters<ImageModelV3['doGenerate']>[0],
114	  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
115	    const { body, warnings } = await this.getArgs(options);
116	
117	    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
118	    const combinedHeaders = combineHeaders(
119	      await resolve(this.config.headers),
120	      options.headers,
121	    );
122	
123	    const { value: multipartResult, responseHeaders } = await postToApi({
124	      url: `${this.config.baseURL}/job?price=true`,
125	      headers: {
126	        ...combinedHeaders,
127	        Accept: 'multipart/form-data; image/png',
128	        'Content-Type': 'application/json',
129	      },
130	      body: {
131	        content: JSON.stringify(body),
132	        values: body,
133	      },
134	      failedResponseHandler: prodiaFailedResponseHandler,
135	      successfulResponseHandler: createMultipartResponseHandler(),
136	      abortSignal: options.abortSignal,
137	      fetch: this.config.fetch,
138	    });
139	
140	    const { jobResult, imageBytes } = multipartResult;
141	
142	    return {
143	      images: [imageBytes],
144	      warnings,
145	      providerMetadata: {
146	        prodia: {
147	          images: [buildProdiaProviderMetadata(jobResult)],
148	        },
149	      },
150	      response: {
