159	const stylePresets = [
160	  '3d-model',
161	  'analog-film',
162	  'anime',
163	  'cinematic',
164	  'comic-book',
165	  'digital-art',
166	  'enhance',
167	  'fantasy-art',
168	  'isometric',
169	  'line-art',
