45	    'Content-Type: image/png\r\n',
46	    '\r\n',
47	  ];
48	
49	  const headerPart = Buffer.from(parts.join(''));
50	  const endPart = Buffer.from(`\r\n--${boundary}--\r\n`);
51	
52	  const body = Buffer.concat([headerPart, imageBuffer, endPart]);
53	
54	  return {
55	    body,
56	    contentType: `multipart/form-data; boundary=${boundary}`,
57	  };
58	}
