- **`maxImagesPerCall`**: Set to `4`
- **API endpoint**: `POST {baseURL}/images/generations`
- **Request body**: `{ model, prompt, n, size, style, pixel_density }` -- where `style` and `pixel_density` come from provider options
- **Response schema**: `{ data: [{ b64_json: string }], created: number }` -- images returned as base64 strings
- **Warnings**: Emit `unsupported` warnings for `aspectRatio`, `seed`, `files`, and `mask` when provided
- **Provider options**: `style` (enum "pixel" | "retro" | "8bit") and `pixelDensity` (number 1-4) via `providerOptions.pixelart`

```typescript
import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtModelConfig } from './pixelart-api';
import { pixelartFailedResponseHandler } from './pixelart-api';
import type { PixelArtImageModelId } from './pixelart-image-settings';

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { prompt, n, size, aspectRatio, seed, files, mask, providerOptions, headers, abortSignal } = options;
    const warnings: Array<SharedV3Warning> = [];

    // Warn on unsupported features
    if (aspectRatio != null) {
      warnings.push({ type: 'unsupported', feature: 'aspectRatio', details: 'PixelArt does not support aspectRatio. Use size instead.' });
    }
    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed', details: 'PixelArt does not support seed.' });
    }
    if (files != null && files.length > 0) {
      warnings.push({ type: 'unsupported', feature: 'files', details: 'PixelArt does not support image editing.' });
    }
    if (mask != null) {
      warnings.push({ type: 'unsupported', feature: 'mask', details: 'PixelArt does not support inpainting masks.' });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
      size,
    };
    if (pixelartOptions?.style !== undefined) {
      body.style = pixelartOptions.style;
    }
    if (pixelartOptions?.pixelDensity !== undefined) {
      body.pixel_density = pixelartOptions.pixelDensity;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        headers,
      ),
      body,
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelartResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.data.map(item => item.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Provider options schema
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      pixelDensity: z.number().int().min(1).max(4).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;

// Response schema
const pixelartResponseSchema = zodSchema(
  z.object({
    data: z.array(z.object({ b64_json: z.string() })),
    created: z.number(),
  }),
);
```

Key patterns being followed:
- `combineHeaders` + `resolve` for merging provider and request headers (same as Prodia line 118-121, BFL line 187-190)
- `postJsonToApi` with `createJsonResponseHandler` for JSON flow (same as fal line 157-170)
- `parseProviderOptions` for provider-specific options (same as Prodia line 44-48, BFL line 86-90)
- `lazySchema()` + `zodSchema()` + `z.object()` for schema definition (same as Prodia line 179-208)
- `_internal.currentDate` for testable timestamps (same as Prodia line 117, BFL line 186)
- Images returned as `Array<string>` (base64) -- the `ImageModelV3` interface accepts `Array<string> | Array<Uint8Array>`

#### 2e. `packages/pixelart/src/pixelart-provider.ts`

Follow the exact pattern from `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775507088418-3a79wi/packages/black-forest-labs/src/black-forest-labs-provider.ts` (image-only provider):

```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import type { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
  /** @deprecated Use `embeddingModel` instead. */
  textEmbeddingModel(modelId: string): never;
}

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3',
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

export const pixelArt = createPixelArt();
```

