import { NoSuchModelError } from '@ai-sdk/provider';
import { describe, expect, it } from 'vitest';
import { createPixelArt } from './pixelart-provider';

describe('createPixelArt', () => {
  const provider = createPixelArt({ apiKey: 'test-key' });

  it('has specificationVersion v3', () => {
    expect(provider.specificationVersion).toBe('v3');
  });

  describe('image', () => {
    it('creates an image model via .image()', () => {
      const model = provider.image('pixelart-standard');

      expect(model.modelId).toBe('pixelart-standard');
      expect(model.provider).toBe('pixelart.image');
      expect(model.specificationVersion).toBe('v3');
    });

    it('creates an image model via .imageModel()', () => {
      const model = provider.imageModel('pixelart-hd');

      expect(model.modelId).toBe('pixelart-hd');
      expect(model.provider).toBe('pixelart.image');
      expect(model.specificationVersion).toBe('v3');
    });
  });

  describe('languageModel', () => {
    it('throws NoSuchModelError', () => {
      expect(() => provider.languageModel('any-model')).toThrow(
        NoSuchModelError,
      );
    });
  });

  describe('embeddingModel', () => {
    it('throws NoSuchModelError', () => {
      expect(() => provider.embeddingModel('any-model')).toThrow(
        NoSuchModelError,
      );
    });
  });

  describe('textEmbeddingModel', () => {
    it('throws NoSuchModelError', () => {
      expect(() => provider.textEmbeddingModel('any-model')).toThrow(
        NoSuchModelError,
      );
    });
  });
});

